sql:
SELECT DISTINCT ol.location_category, ol.location_size
FROM offense_locations ol
JOIN incidents i ON ol.location_id = i.offense_location;

SELECT * 
FROM bias_motivations 
WHERE bias_id = 1;

SELECT COUNT(*) 
FROM incident_access 
WHERE user_id = 0;

SELECT incident_id
FROM incidents
WHERE number_offenders_u18 = (SELECT MAX(number_offenders_u18) FROM incidents);

SELECT incident_id
FROM incident_access
WHERE access_type = 'edit';

external_knowledge:
- 'storms' metaphorically represent incidents;
- 'public squares' refers to incidents occurring in public locations;
- 'witnessed by multiple pairs of discerning eyes' indicates the incidents have been accessed by more than one user;
- 'roots of the storms that have yet to settle' means the incidents are ongoing;
- 'tale of each tempest' refers to the detailed information about each incident, including date, day of week, number of victims, race/ethnicity, offense name, and bias motivation;
- 'where it raged' refers to the location details (city, state, and country);
- 'depth of its fury' refers to the impact of the incident, including number of victims over and under 18;
- 'shadows cast by its wrath' refers to the race/ethnicity information of the offender;
- 'names of the winds that stirred it' refers to the type of offense committed;
- 'faces of those who dared to glimpse the chaos' refers to the users who accessed the incident information.

